#!/bin/zsh
# Download all 45 Stitch screen HTML code files
set -e
BASE_DIR="$(dirname "$0")"
HTML_DIR="$BASE_DIR/html"
mkdir -p "$HTML_DIR"

dl() {
  local slug="$1" url="$2"
  local out="$HTML_DIR/${slug}.html"
  if [ -f "$out" ]; then echo "EXISTS: $slug"; return; fi
  echo "Downloading: $slug"
  curl -sL -o "$out" "$url" || echo "  FAILED: $slug"
}

